#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Bosses;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.Vanilla.Entities;
using PVZEngine.Auras;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.balloon)]
    public class Balloon : EntityBehaviourDefinition
    {
        public Balloon(string nsp, string name) : base(nsp, name)
        {
            AddAura(new DragAura());
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            var buff = entity.AddBuff<FlyBuff>();
            buff.SetProperty(FlyBuff.PROP_TARGET_HEIGHT, 120f);
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (entity.Parent != null)
            {
                DragParent(entity, entity.Parent);
            }
        }
        public override void PostDeath(Entity entity, DeathInfo deathInfo)
        {
            base.PostDeath(entity, deathInfo);
            var parent = entity.Parent;
            if (parent != null && parent.IsEntityOf(VanillaBossID.lockedChest))
            {
                LockedChest.Stun(parent, 10);
            }
        }
        public static void DragParent(Entity entity, Entity parent)
        {
            parent.SetCenter(entity.Position + Vector3.back * 3);
        }
        public class DragAura : AuraEffectDefinition
        {
            public DragAura() : base(VanillaBuffID.Entity.draggedByBalloon, 1)
            {
            }

            public override void GetAuraTargets(AuraEffect auraEffect, List<IBuffTarget> results)
            {
                var source = auraEffect.Source.GetEntity();
                if (source == null)
                    return;
                if (source.Parent != null)
                {
                    results.Add(source.Parent);
                }
            }
        }
    }
}
